#include<iostream>#include<vector>#include<algorithm>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n,k;        cin>>n>>k;        vector<ll> a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        sort(a.begin(),a.end());        ll ans=0;        vector<ll> prefix(n);        prefix[0]=a[0];        for(int i=1;i<n;i++){            prefix[i]=prefix[i-1]+a[i];        }        for(int i=0;i<=k;i++){            ll sum=0;                        int left= 2*i;            int right= n - 1 - (k - i);            sum+= prefix[right] - (left > 0 ? prefix[left-1] : 0);                ans=max(ans,sum);        }        cout<<ans<<"\n";     }}